function renderSlider(id){const vals=$$('[data-sim-slider]').map(x=>+x.value),avg=Math.round(vals.reduce((a,b)=>a+b,0)/vals.length);let title='',msg='';if(id==='neural'){title='Prediction confidence '+avg+'%';msg='More useful examples and better weights usually improve AI predictions.'}else if(id==='fair'){const fair=100-Math.abs(vals[0]-vals[1]);title='Fairness score '+fair+'%';msg='Balanced data helps AI treat groups more fairly. Accuracy estimate: '+avg+'%.'}else{title=avg>70?'AI action: Emergency mode':avg>45?'AI action: Balanced control':'AI action: Eco saving mode';msg='AI uses sensor data to recommend a safe smart-city action.'}$('#simVisual').innerHTML='<h2>'+title+'</h2><div class="meter"><i style="width:'+avg+'%"></i></div><p>'+vals.join(' • ')+'</p>';$('#simResult').textContent=msg}
function promptSim(){$('#simStage').innerHTML='<h3>Prompt Builder</h3><div class="sim-shell"><div class="controls"><label>Role<input id="pRole" value="friendly AI teacher"></label><label>Task<input id="pTask" value="explain machine learning"></label><label>Audience<input id="pAudience" value="Class 8 students"></label><label>Format<input id="pFormat" value="5 easy bullet points"></label><label>Safety<input id="pSafety" value="include one safe AI rule"></label><button class="btn primary" id="buildPrompt">Build Prompt</button></div><div class="result" id="promptOut"></div></div>';const run=()=>$('#promptOut').textContent='You are a '+$('#pRole').value+'. Please '+$('#pTask').value+' for '+$('#pAudience').value+'. Use '+$('#pFormat').value+', one school example, simple words, and '+$('#pSafety').value+'.';$('#buildPrompt').onclick=run;run()}
function visionSim(){
  const SIZE=5;
  $('#simStage').innerHTML='<h3>Pixel Vision</h3><div class="sim-shell"><div class="controls"><p style="font-weight:900;margin:0 0 10px">Draw a pattern, then ask the AI to classify it.</p><div class="tile-grid" id="pixelGrid"></div><button class="btn primary" id="classifyBtn" style="margin-top:14px">Classify pattern</button><button class="btn secondary" id="clearPixelBtn" style="margin-top:8px">Clear grid</button></div><div><div class="visual" id="simVisual"><h2>Draw something!</h2><p>Click squares to toggle pixels on and off, then classify your pattern.</p></div><div class="result" id="simResult">Tip: try a filled block, a symmetric shape, and a scattered pattern to see different results.</div></div></div>';
  const grid=$('#pixelGrid');
  const cells=[];
  for(let i=0;i<SIZE*SIZE;i++){
    const c=document.createElement('div');
    c.className='tile';
    c.onclick=()=>{c.classList.toggle('on')};
    grid.appendChild(c);
    cells.push(c);
  }
  $('#clearPixelBtn').onclick=()=>{cells.forEach(c=>c.classList.remove('on'))};
  $('#classifyBtn').onclick=()=>{
    const on=cells.filter(c=>c.classList.contains('on'));
    const count=on.length;
    let label='Pattern', msg='';
    if(count===0){
      label='Empty canvas';
      msg='No pixels are switched on, so the AI has nothing to classify yet.';
    }else{
      let symmetric=true;
      for(let r=0;r<SIZE;r++){
        for(let c=0;c<SIZE;c++){
          const leftOn=cells[r*SIZE+c].classList.contains('on');
          const rightOn=cells[r*SIZE+(SIZE-1-c)].classList.contains('on');
          if(leftOn!==rightOn)symmetric=false;
        }
      }
      const density=count/(SIZE*SIZE);
      if(density>0.6){label='Dense blob';msg='Most pixels are on, so the AI reads this as a solid, filled shape.';}
      else if(symmetric){label='Symmetric pattern';msg='Left and right sides match, so the AI flags this as a balanced, symmetric shape (like a face or letter).';}
      else{label='Irregular pattern';msg='The pixels are scattered without symmetry, so the AI treats this as a unique, irregular shape.';}
    }
    $('#simVisual').innerHTML='<h2>'+label+'</h2><p>'+count+' of '+(SIZE*SIZE)+' pixels are on.</p>';
    $('#simResult').textContent=msg;
  };
}
function neuralSim(){
$('#simStage').innerHTML = `
<div class="nn-container">
  <div class="nn-header">
    <div class="nn-title">Neural network — cat vs dog classifier</div>
    <div class="nn-epoch-badge" id="nnEpochBadge">Epoch 0 / 100</div>
  </div>
  <div class="nn-controls">
    <button class="nn-btn-primary" id="nnTrainBtn">▶ Train</button>
    <button class="nn-btn-secondary" id="nnResetBtn">Reset</button>
    <button class="nn-btn-secondary" id="nnNextBtn">Next sample</button>
    <div class="nn-speed-wrap">
      <span class="nn-speed-label">Speed</span>
      <input type="range" id="nnSpeedSlider" min="1" max="10" value="4" step="1">
      <span class="nn-speed-label" id="nnSpeedLabel">4×</span>
    </div>
  </div>
  <div class="nn-stats-row">
    <div class="nn-stat-card"><div class="nn-stat-label">Loss</div><div class="nn-stat-value" id="nnLossVal">—</div></div>
    <div class="nn-stat-card"><div class="nn-stat-label">Accuracy</div><div class="nn-stat-value" id="nnAccVal">—</div></div>
    <div class="nn-stat-card"><div class="nn-stat-label">Learning rate</div><div class="nn-stat-value" id="nnLrVal">0.1</div></div>
  </div>
  <div class="nn-main-grid">
    <div class="nn-network-wrap"><canvas class="nn-canvas-net" id="nnNetCanvas" width="420" height="280"></canvas></div>
    <div class="nn-side-panel">
      <div class="nn-sample-display">
        <div class="nn-sample-title">Current sample</div>
        <span class="nn-animal-emoji" id="nnAnimalEmoji">🐱</span>
        <div class="nn-sample-title" style="margin-top:8px">Features</div>
        <div class="nn-sample-features" id="nnFeaturesDiv"></div>
      </div>
      <div class="nn-prediction-box">
        <div class="nn-pred-title">Network output</div>
        <div class="nn-pred-row"><span class="nn-pred-animal">🐱 Cat</span><span class="nn-pred-pct" id="nnCatPct">—</span></div>
        <div class="nn-pred-bar-wrap"><div class="nn-pred-bar" id="nnCatBar" style="width:50%;background:#1D9E75"></div></div>
        <div class="nn-pred-row"><span class="nn-pred-animal">🐶 Dog</span><span class="nn-pred-pct" id="nnDogPct">—</span></div>
        <div class="nn-pred-bar-wrap"><div class="nn-pred-bar" id="nnDogBar" style="width:50%;background:#7F77DD"></div></div>
        <div class="nn-verdict" id="nnVerdict"></div>
      </div>
    </div>
  </div>
  <div class="nn-loss-section">
    <div class="nn-loss-header"><span class="nn-loss-title">Training loss curve</span><span class="nn-loss-title" id="nnTrainStatus"></span></div>
    <canvas class="nn-canvas-loss" id="nnLossCanvas" width="660" height="84"></canvas>
  </div>
  <div class="nn-explanation-box"><div class="nn-explanation-text" id="nnExplanationText">
    <strong>How it works:</strong> This network has 4 inputs (fur length, ear shape, tail length, size) → 4 hidden neurons → 1 output (0 = cat, 1 = dog). Click <strong>Train</strong> to watch it learn from 20 synthetic examples using backpropagation. The glowing edges show which connections fire most strongly for the current sample.
  </div></div>
</div>`;

const FEATURES=['Fur length','Ear shape','Tail length','Body size'];
const FEAT_COLORS=['#1D9E75','#7F77DD','#EF9F27','#D85A30'];
function sigmoid(x){return 1/(1+Math.exp(-x))}
function sigmoidD(x){const s=sigmoid(x);return s*(1-s)}

const SAMPLES=Array.from({length:20},(_,i)=>{
  const isCat=i<10;
  return{
    label:isCat?0:1, emoji:isCat?'🐱':'🐶', name:isCat?'Cat':'Dog',
    x:isCat
      ?[0.3+Math.random()*0.35,0.6+Math.random()*0.3,0.2+Math.random()*0.3,0.25+Math.random()*0.3]
      :[0.55+Math.random()*0.4,0.2+Math.random()*0.35,0.6+Math.random()*0.35,0.55+Math.random()*0.4]
  };
});

let W1,b1,W2,b2;
function initNetwork(){
  W1=Array.from({length:4},()=>Array.from({length:4},()=>(Math.random()-0.5)*0.5));
  b1=Array(4).fill(0);
  W2=Array.from({length:4},()=>(Math.random()-0.5)*0.5);
  b2=0;
}
function forward(x){
  const z1=W1.map((row,j)=>row.reduce((s,w,i)=>s+w*x[i],0)+b1[j]);
  const a1=z1.map(sigmoid);
  const z2=W2.reduce((s,w,j)=>s+w*a1[j],0)+b2;
  const a2=sigmoid(z2);
  return{z1,a1,z2,a2};
}
function trainStep(sample,lr){
  const{x,label}=sample;
  const{z1,a1,z2,a2}=forward(x);
  const loss=-label*Math.log(a2+1e-9)-(1-label)*Math.log(1-a2+1e-9);
  const d2=a2-label;
  W2.forEach((_,j)=>{W2[j]-=lr*d2*a1[j]});
  b2-=lr*d2;
  a1.forEach((_,j)=>{
    const dz1=d2*W2[j]*sigmoidD(z1[j]);
    x.forEach((_,i)=>{W1[j][i]-=lr*dz1*x[i]});
    b1[j]-=lr*dz1;
  });
  return loss;
}

let epoch=0, training=false, lossHistory=[], currentSampleIdx=0, intervalId=null;

function getAccuracy(){let correct=0;SAMPLES.forEach(s=>{const{a2}=forward(s.x);correct+=(Math.round(a2)===s.label?1:0)});return correct/SAMPLES.length}
function getAvgLoss(){let l=0;SAMPLES.forEach(s=>{const{a2}=forward(s.x);l+=-s.label*Math.log(a2+1e-9)-(1-s.label)*Math.log(1-a2+1e-9)});return l/SAMPLES.length}

function toggleTraining(){
  training=!training;
  const btn=$('#nnTrainBtn');
  if(training){
    btn.textContent='⏸ Pause';
    $('#nnTrainStatus').innerHTML='<span class="nn-training-dot"></span>Training...';
    runTraining();
  }else{
    btn.textContent='▶ Resume';
    $('#nnTrainStatus').textContent='Paused';
    clearInterval(intervalId);
  }
}
function runTraining(){
  clearInterval(intervalId);
  const speed=parseInt($('#nnSpeedSlider').value);
  intervalId=setInterval(()=>{
    if(!training||epoch>=100){clearInterval(intervalId);if(epoch>=100){$('#nnTrainBtn').textContent='✓ Done';$('#nnTrainBtn').disabled=true;$('#nnTrainStatus').textContent='Complete!';training=false}return}
    for(let i=0;i<speed;i++){
      if(epoch>=100)break;
      const lr=0.1;
      SAMPLES.forEach(s=>trainStep(s,lr));
      epoch++;
    }
    const loss=getAvgLoss(), acc=getAccuracy();
    lossHistory.push(loss);
    updateStats(loss,acc);
    updateDisplay();
    if(epoch>=100){clearInterval(intervalId);$('#nnTrainBtn').textContent='✓ Done';$('#nnTrainBtn').disabled=true;$('#nnTrainStatus').textContent='Training complete!';training=false;updateExplanation(acc);addProgress('sims','neural')}
  },60);
}
$('#nnSpeedSlider').oninput=function(){
  $('#nnSpeedLabel').textContent=this.value+'×';
  if(training){clearInterval(intervalId);runTraining()}
};
function updateStats(loss,acc){
  const lv=$('#nnLossVal');
  lv.textContent=loss.toFixed(3);
  lv.className='nn-stat-value '+(loss>0.5?'bad':loss>0.2?'med':'good');
  const av=$('#nnAccVal');
  av.textContent=Math.round(acc*100)+'%';
  av.className='nn-stat-value '+(acc>=0.9?'good':acc>=0.7?'med':'bad');
  $('#nnEpochBadge').textContent='Epoch '+epoch+' / 100';
  drawLoss();
}
function nextSample(){currentSampleIdx=(currentSampleIdx+1)%SAMPLES.length;updateDisplay()}
function updateDisplay(){
  const s=SAMPLES[currentSampleIdx];
  $('#nnAnimalEmoji').textContent=s.emoji;
  $('#nnFeaturesDiv').innerHTML=s.x.map((v,i)=>'<div class="nn-feature-row"><span class="nn-feature-name">'+FEATURES[i]+'</span><div class="nn-feature-bar-wrap"><div class="nn-feature-bar" style="width:'+Math.round(v*100)+'%;background:'+FEAT_COLORS[i]+'"></div></div></div>').join('');
  const{a1,a2}=forward(s.x);
  const catP=1-a2, dogP=a2;
  $('#nnCatPct').textContent=Math.round(catP*100)+'%';
  $('#nnDogPct').textContent=Math.round(dogP*100)+'%';
  $('#nnCatBar').style.width=Math.round(catP*100)+'%';
  $('#nnDogBar').style.width=Math.round(dogP*100)+'%';
  const pred=Math.round(a2), correct=(pred===s.label);
  const v=$('#nnVerdict');
  v.textContent=correct?'✓ Correct':'✗ Wrong';
  v.className='nn-verdict '+(correct?'correct':'wrong');
  drawNetwork(s.x,a1,a2);
}
function resetAll(){
  clearInterval(intervalId);training=false;epoch=0;lossHistory=[];currentSampleIdx=0;
  initNetwork();
  $('#nnTrainBtn').textContent='▶ Train';$('#nnTrainBtn').disabled=false;
  $('#nnTrainStatus').textContent='';
  $('#nnLossVal').textContent='—';$('#nnAccVal').textContent='—';
  $('#nnEpochBadge').textContent='Epoch 0 / 100';
  $('#nnCatPct').textContent='—';$('#nnDogPct').textContent='—';
  $('#nnCatBar').style.width='50%';$('#nnDogBar').style.width='50%';
  $('#nnVerdict').textContent='';$('#nnVerdict').className='nn-verdict';
  $('#nnExplanationText').innerHTML='<strong>How it works:</strong> This network has 4 inputs (fur length, ear shape, tail length, size) → 4 hidden neurons → 1 output (0 = cat, 1 = dog). Click <strong>Train</strong> to watch it learn from 20 synthetic examples using backpropagation. The glowing edges show which connections fire most strongly for the current sample.';
  drawLoss();updateDisplay();
}
function drawNetwork(inputs,hidden,output){
  const canvas=$('#nnNetCanvas');
  const ctx=canvas.getContext('2d');
  const W=canvas.width, H=canvas.height;
  ctx.clearRect(0,0,W,H);
  const textColor='rgba(20,32,51,0.75)';
  const bgColor='rgba(20,32,51,0.06)';
  const layers=[
    {x:70,nodes:inputs.map((v,i)=>({val:v,label:FEATURES[i].split(' ')[0],color:FEAT_COLORS[i]}))},
    {x:210,nodes:hidden.map((v,i)=>({val:v,label:'H'+(i+1),color:'#7F77DD'}))},
    {x:350,nodes:[{val:output,label:'Output',color:output>0.5?'#7F77DD':'#1D9E75'}]}
  ];
  const nodeR=18;
  layers.forEach(layer=>{const n=layer.nodes.length;layer.nodes.forEach((node,ni)=>{node.y=H/2+(ni-(n-1)/2)*62})});
  for(let li=0;li<layers.length-1;li++){
    const src=layers[li], dst=layers[li+1];
    src.nodes.forEach((sn,si)=>{
      dst.nodes.forEach((dn,di)=>{
        const w=li===0?W1[di][si]:W2[di];
        const strength=Math.abs(w)*sn.val;
        const alpha=Math.min(0.85,0.08+strength*0.6);
        const positive=(li===0?W1[di][si]:W2[di])>0;
        ctx.beginPath();
        ctx.moveTo(src.x+nodeR,sn.y);
        ctx.lineTo(dst.x-nodeR,dn.y);
        ctx.strokeStyle=positive?'rgba(29,158,117,'+alpha+')':'rgba(168,45,45,'+alpha+')';
        ctx.lineWidth=0.5+strength*2.5;
        ctx.stroke();
      });
    });
  }
  layers.forEach((layer,li)=>{
    layer.nodes.forEach(node=>{
      const{val,label,color}=node, x=layer.x, y=node.y;
      ctx.beginPath();ctx.arc(x,y,nodeR,0,Math.PI*2);ctx.fillStyle=bgColor;ctx.fill();
      ctx.beginPath();ctx.arc(x,y,nodeR,0,Math.PI*2);
      const alpha=0.15+val*0.75;
      ctx.strokeStyle=color;ctx.lineWidth=1.5+val*2;ctx.globalAlpha=alpha;ctx.stroke();ctx.globalAlpha=1;
      ctx.beginPath();ctx.arc(x,y,nodeR*0.75,0,Math.PI*2);ctx.fillStyle=color;ctx.globalAlpha=val*0.7;ctx.fill();ctx.globalAlpha=1;
      ctx.fillStyle=textColor;ctx.font='600 10px Inter,sans-serif';ctx.textAlign='center';ctx.textBaseline='middle';
      ctx.fillText(li===2?(val>0.5?'🐶':'🐱'):label,x,y);
      ctx.font='400 9px Inter,sans-serif';ctx.fillStyle='rgba(20,32,51,0.45)';
      ctx.fillText(val.toFixed(2),x,y+nodeR+10);
    });
  });
  const layerNames=['Input layer','Hidden layer','Output'];
  layers.forEach((layer,li)=>{
    ctx.font='600 10px Inter,sans-serif';ctx.fillStyle='rgba(20,32,51,0.45)';ctx.textAlign='center';
    ctx.fillText(layerNames[li],layer.x,18);
  });
}
function drawLoss(){
  const canvas=$('#nnLossCanvas');
  const ctx=canvas.getContext('2d');
  const W=canvas.width, H=canvas.height;
  ctx.clearRect(0,0,W,H);
  if(lossHistory.length<2)return;
  const pad={l:36,r:16,t:10,b:20};
  const cW=W-pad.l-pad.r, cH=H-pad.t-pad.b;
  const maxL=Math.max(...lossHistory,0.7), minL=0;
  const xScale=cW/(100-1), yScale=cH/(maxL-minL);
  [0.2,0.4,0.6].forEach(v=>{
    const y=pad.t+cH-v*yScale;
    ctx.beginPath();ctx.moveTo(pad.l,y);ctx.lineTo(pad.l+cW,y);
    ctx.strokeStyle='rgba(20,32,51,0.08)';ctx.lineWidth=0.5;ctx.setLineDash([3,3]);ctx.stroke();ctx.setLineDash([]);
    ctx.font='9px Inter,sans-serif';ctx.fillStyle='rgba(20,32,51,0.4)';ctx.textAlign='right';ctx.fillText(v.toFixed(1),pad.l-4,y+3);
  });
  ctx.beginPath();
  lossHistory.forEach((l,i)=>{
    const px=pad.l+i*xScale, py=pad.t+cH-(l-minL)*yScale;
    i===0?ctx.moveTo(px,py):ctx.lineTo(px,py);
  });
  ctx.strokeStyle='#E24B4A';ctx.lineWidth=1.5;ctx.stroke();
  const last=lossHistory[lossHistory.length-1];
  const lx=pad.l+(lossHistory.length-1)*xScale, ly=pad.t+cH-(last-minL)*yScale;
  ctx.beginPath();ctx.arc(lx,ly,3,0,Math.PI*2);ctx.fillStyle='#E24B4A';ctx.fill();
}
function updateExplanation(acc){
  const pct=Math.round(acc*100);
  let msg='';
  if(pct>=95)msg='<strong>Excellent!</strong> The network achieved <strong>'+pct+'% accuracy</strong>. It has learned strong decision boundaries — green edges carry cat-like features, red edges suppress them. The hidden layer neurons act as feature detectors: some fire for long tails, others for upright ears.';
  else if(pct>=80)msg='<strong>Good progress!</strong> At <strong>'+pct+'% accuracy</strong>, the network mostly separates cats from dogs. A few ambiguous samples still confuse it — those with medium fur length or neutral ear shapes land near the decision boundary.';
  else msg='<strong>Still learning.</strong> At <strong>'+pct+'% accuracy</strong>, the network is finding patterns but struggling. Try resetting and training again — random initialization sometimes puts weights in a poor region of the loss landscape.';
  $('#nnExplanationText').innerHTML=msg;
}

$('#nnTrainBtn').onclick=toggleTraining;
$('#nnResetBtn').onclick=resetAll;
$('#nnNextBtn').onclick=nextSample;

initNetwork();
updateDisplay();
drawLoss();
}


