function initGames(){ $('#gameTabs').innerHTML=games.map((g,i)=>'<button class="tab '+(i===0?'active':'')+'" data-i="'+i+'">'+g[1]+'<small>'+g[2]+'</small></button>').join(''); $$('#gameTabs .tab').forEach(b=>b.onclick=()=>openGame(+b.dataset.i)); openGame(0)}
function gameShell(g){
  addProgress('games',g[0]);
  $$('#gameTabs .tab').forEach(x=>x.classList.remove('active'));
  $$('#gameTabs .tab')[games.findIndex(x=>x[0]===g[0])].classList.add('active');
  const embedded = g[0]==='quiz' || g[0]==='robot' || g[0]==='balance' || g[0]==='pixel' || g[0]==='htmldebugger' || g[0]==='repairshop' || g[0]==='gamemaker';
  if(embedded){
    $('#gameStage').innerHTML='<h3>'+g[1]+'</h3><p>'+g[2]+'</p><div class="game-layout"><div class="game-frame-wrap"></div></div><div class="actions" style="margin-top:14px"><button class="btn primary" id="restartGame">Restart</button></div>';
  }else{
    $('#gameStage').innerHTML='<h3>'+g[1]+'</h3><p>'+g[2]+'</p><div class="game-layout"><div class="game-board" id="gameBoard"></div><div class="scorebox"><div>Score</div><div class="bigscore" id="score">0</div><div class="result" id="gameInfo"></div><button class="btn primary" id="restartGame">Restart</button></div></div>';
  }
  $('#restartGame').onclick=()=>openGame(games.findIndex(x=>x[0]===g[0]))
}
