const compilerLinks={html:'https://codepen.io/pen/',css:'https://codepen.io/pen/',javascript:'https://playcode.io/javascript',python:'https://www.programiz.com/python-programming/online-compiler/',cpp:'https://www.programiz.com/cpp-programming/online-compiler/',c:'https://www.programiz.com/c-programming/online-compiler/',java:'https://www.programiz.com/java-programming/online-compiler/',php:'https://www.programiz.com/php/online-compiler/',ruby:'https://www.programiz.com/ruby/online-compiler/',go:'https://www.programiz.com/golang/online-compiler/',rust:'https://www.programiz.com/rust/online-compiler/',swift:'https://www.programiz.com/swift/online-compiler/',kotlin:'https://www.programiz.com/kotlin/online-compiler/',sql:'https://sqliteonline.com/'};
const templates={html:'<h1>Hello AI4All</h1>\n<p>I am learning AI and coding.</p>\n<button onclick="alert(\'Great job!\')">Click me</button>',css:'body { font-family: sans-serif; background: #eef2ff; }\nh1 { color: #5b4bff; }\n.card { padding: 20px; border-radius: 20px; background: white; }',javascript:'let name = "Student";\nconsole.log("Hello " + name);\nfor (let i = 1; i <= 3; i++) {\n  console.log("AI idea " + i);\n}',python:'name = "Student"\nprint("Hello", name)\nprint("AI helps us learn patterns")',cpp:'#include <iostream>\nusing namespace std;\nint main(){ cout << "Hello AI4All"; return 0; }',c:'#include <stdio.h>\nint main(){ printf("Hello AI4All"); return 0; }',java:'class Main { public static void main(String[] args) { System.out.println("Hello AI4All"); } }',php:'<?php echo "Hello AI4All"; ?>',ruby:'puts "Hello AI4All"',go:'package main\nimport "fmt"\nfunc main(){ fmt.Println("Hello AI4All") }',rust:'fn main(){ println!("Hello AI4All"); }',swift:'print("Hello AI4All")',kotlin:'fun main(){ println("Hello AI4All") }',sql:'CREATE TABLE students(name TEXT);\nINSERT INTO students VALUES ("AI learner");\nSELECT * FROM students;'};
function initCode(){const langs=Object.keys(templates);$('#language').innerHTML=langs.map(l=>'<option value="'+l+'">'+l.toUpperCase()+'</option>').join('');$('#challenge').innerHTML='<option>Basic output</option><option>AI idea</option><option>Student project</option>';$('#language').onchange=setCode;$('#challenge').onchange=setCode;$('#runCode').onclick=()=>runCode(true);$('#resetCode').onclick=setCode;setCode()}
function setCode(){const lang=$('#language').value;$('#editor').value=templates[lang];$('#openCompiler').href=compilerLinks[lang];$('#challengeText').textContent='Practice '+$('#challenge').value+' in '+lang.toUpperCase()+'.';$('#codeTips').textContent=(['html','css','javascript','python'].includes(lang)?'This runs in this page.':'Use the full compiler link for complete '+lang.toUpperCase()+' execution.');runCode(false)}
function runCode(count){const lang=$('#language').value,code=$('#editor').value;$('#preview').style.display='none';$('#output').style.display='block';let out='';try{if(lang==='html'){$('#preview').style.display='block';$('#output').style.display='none';$('#preview').srcdoc=code}else if(lang==='css'){$('#preview').style.display='block';$('#output').style.display='none';$('#preview').srcdoc='<style>'+code.replace(/<\/style/gi,'<\\/style')+'</style><h1>CSS Preview</h1><p>Style is working.</p>'}else if(lang==='javascript'){const logs=[];new Function('console',code)({log:(...a)=>logs.push(a.join(' '))});out=logs.join('\n')||'Code ran successfully.'}else if(lang==='python'){out=runMiniPython(code)}else{out='Template ready. Open the free compiler for full '+lang.toUpperCase()+' running.'}}catch(e){out='Error: '+e.message}$('#output').textContent=out;if(count)addProgress('code')}
function runMiniPython(code){let vars={},out=[];for(const raw of code.split('\n')){const line=raw.trim();if(!line||line.startsWith('#'))continue;if(line.includes('=')&&!line.startsWith('print')){const parts=line.split('=');vars[parts[0].trim()]=parts.slice(1).join('=').trim().replace(/^['"]|['"]$/g,'');continue}if(line.startsWith('print')){const inside=line.slice(line.indexOf('(')+1,line.lastIndexOf(')'));out.push(inside.split(',').map(p=>vars[p.trim()]??p.trim().replace(/^['"]|['"]$/g,'')).join(' '))}}return out.join('\n')||'Python beginner code ran.'}
function updateDash(){if(!$('#vDone'))return;$('#vDone').textContent=progress.videos.length;$('#sDone').textContent=progress.sims.length;$('#gDone').textContent=progress.games.length;$('#cDone').textContent=progress.code;const done=progress.videos.length+progress.sims.length+progress.games.length+Math.min(progress.code,20),total=allVideos.length+simDefs.length+games.length+20;$('#progressBar').style.width=Math.round(done/total*100)+'%'}
